import React from 'react';
import { Link } from 'react-router-dom';
import './Programs.css';

const Programs = () => {
  const programs = [
    {
      title: 'STRENGTH TRAINING',
      description: 'Build muscle and increase strength with our comprehensive weight training programs.',
      icon: '💪',
      color: '#dc2626'
    },
    {
      title: 'WEIGHT LOSS',
      description: 'Achieve your weight loss goals with personalized nutrition and workout plans.',
      icon: '🔥',
      color: '#dc2626'
    },
    {
      title: 'PERSONAL TRAINING',
      description: 'One-on-one coaching with expert trainers for maximum results.',
      icon: '👥',
      color: '#dc2626'
    },
    {
      title: 'CROSSFIT',
      description: 'High-intensity functional training for all fitness levels.',
      icon: '⚡',
      color: '#dc2626'
    },
    {
      title: 'HIIT',
      description: 'Quick, intense workouts to boost metabolism and burn fat.',
      icon: '⏱️',
      color: '#dc2626'
    },
    {
      title: 'YOGA & FLEXIBILITY',
      description: 'Improve flexibility, balance, and mental focus with our yoga classes.',
      icon: '🧘',
      color: '#dc2626'
    }
  ];

  return (
    <section className="programs-page">
      <div className="container">
        <div className="programs-header">
          <h1 className="page-title">OUR PROGRAMS</h1>
          <p className="page-subtitle">
            Choose from a variety of programs designed to help you achieve your fitness goals
          </p>
        </div>

        <div className="programs-grid">
          {programs.map((program, index) => (
            <div key={index} className="program-card">
              <div className="program-icon">{program.icon}</div>
              <h3>{program.title}</h3>
              <p>{program.description}</p>
              <Link to="/booking" className="program-btn">BOOK NOW</Link>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Programs;
